UPDATE public.questions SET
  stimulus_text = 'The author suggests that the popularity of the novel can be attributed to its depiction of a “destabilizing effect” on society. This is achieved through the novel’s use of “interpolated speech,” or characters’ speech interspersed within the narrative, to create a sense of realism. The author also suggests that this technique is a means for Black American authors to resist the constraints of “externally imposed literary conventions.”  Which of the following best describes the author’s overall purpose in this passage?',
