UPDATE public.questions SET
  stimulus_text = 'The writer''s main point is that the use of social media in the classroom, while potentially beneficial, requires careful consideration. The author suggests that teachers need to think critically about the ways in which social media can be used to support learning and to avoid using it in ways that might distract or disengage students. What is the most likely reason the writer includes the sentence "Teachers need to think critically about the ways in which social media can be used to support learning and to avoid using it in ways that might distract or disengage students?"',
  question_text = 'The author includes the sentence "Teachers need to think critically about the ways in which social media can be used to support learning and to avoid using it in ways that might distract or disengage students" in order to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"provide a specific example of how social media can be used effectively in the classroom.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"acknowledge that there are potential drawbacks to using social media in the classroom.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"offer a solution to the problem of social media distracting students in the classroom.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"suggest that social media should only be used in certain situations.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The sentence directly addresses a potential drawback of using social media in the classroom. It acknowledges that social media, while beneficial in some ways, can also be distracting and disengaging. This helps the author present a balanced perspective on the issue. The passage states that "The writer''s main point is that the use of social media in the classroom, while potentially beneficial, requires careful…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: acknowledge that there are potential drawbacks to using social media in the classroom.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"SYN","domain_id":"expression","opensat_index":1285,"opensat_domain":"Expression of Ideas","opensat_raw_id":"945f2186","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.927Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
